class Solution {
    public int getMinSwaps(String num, int k) {
        int n = num.length();
        int[] count = new int[10];
        for (char c : num.toCharArray()) {
            count[c - '0']++;
        }
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = num.charAt(i) - '0';
        }
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (i + count[arr[i]] - 1 < n - 1) {
                int j = i;
                while (j < n - 1 && arr[j] == arr[i]) {
                    j++;
                }
                int temp = arr[i];
                for (int p = i; p < j; p++) {
                    arr[p] = arr[p + 1];
                }
                arr[j] = temp;
                res += j - i;
            }
        }
        int[] sorted = new int[n];
        for (int i = 0; i < n; i++) {
            sorted[i] = arr[i];
        }
        Arrays.sort(sorted);
        int[] next = new int[n + 1];
        next[0] = 0;
        for (int i = 1; i <= n; i++) {
            next[i] = next[i - 1] + (sorted[i - 1] != sorted[i - 2] ? 1 : 0);
        }
        int[] dp = new int[n + 1];
        for (int i = 0; i <= n; i++) {
            dp[i] = Integer.MAX_VALUE;
        }
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = i - 1; j >= 0; j--) {
                if (next[i] - next[j] == i - j) {
                    dp[i] = Math.min(dp[i], dp[j] + (i - j));
                }
            }
        }
        return dp[n] - 1;
    }
}
